sp_widget.client_script:
api.controller = function($scope, $location) {
    var c = this;

    // Track whether modal is open
    c.showAdvancedSearch = false;

    /* ==============================
       TEXT OPERATORS
    ============================== */
    c.textOperators = [
        { value: 'CONTAINS', label: 'Contains' },
        { value: 'STARTSWITH', label: 'Starts With' },
        { value: '=', label: 'Is' },
        { value: '!=', label: 'Is Not' },
        { value: 'NOT CONTAINS', label: 'Does Not Contain' }
    ];

    /* ==============================
       COLOR OPTIONS CONFIG
    ============================== */
    c.colorOptions = [
        { label: 'White', value: 'W', icon: 'white' },
        { label: 'Blue', value: 'U', icon: 'blue' },
        { label: 'Black', value: 'B', icon: 'black' },
        { label: 'Red', value: 'R', icon: 'red' },
        { label: 'Green', value: 'G', icon: 'green' },
        { label: 'Colorless', value: 'C', icon: 'colorless' }
    ];

    /* ==============================
       ADVANCED QUERY MODEL
    ============================== */
    c.advQuery = {
        nameRules: [],
        textRules: [],
        flavorRules: [],
        artistRules: [],
        typeRules: [],
        rarityRules: [],
        cmcRules: [],
        priceRules: [],
        priceChangeRules: [],
        powerRules: [],
        toughnessRules: [],
        loyaltyRules: [],
        colors: {}
    };

    /* ==============================
       FIELD CONFIGS
    ============================== */
    c.textFieldConfigs = [
        { label: 'Name', model: 'nameRules', placeholder: 'Card name' },
        { label: 'Text', model: 'textRules', placeholder: 'Oracle / rules text' },
        { label: 'Flavor', model: 'flavorRules', placeholder: 'Flavor text' },
        { label: 'Artist', model: 'artistRules', placeholder: 'Artist name' },
        { label: 'Type', model: 'typeRules', placeholder: 'e.g. legendary, creature, artifact' }
    ];

    c.selectFieldConfigs = [
        {
            label: 'Rarity',
            model: 'rarityRules',
            options: [
                { value: 'common', label: 'Common' },
                { value: 'uncommon', label: 'Uncommon' },
                { value: 'rare', label: 'Rare' },
                { value: 'mythic', label: 'Mythic' },
                { value: 'special', label: 'Special' }
            ]
        }
    ];

    c.numericFieldConfigs = [
        { label: 'CMC', model: 'cmcRules', step: null },
        { label: 'Price', model: 'priceRules', step: '0.01' },
        { label: 'Price Change', model: 'priceChangeRules', step: '0.01' },
        { label: 'Power', model: 'powerRules', step: null },
        { label: 'Toughness', model: 'toughnessRules', step: null },
        { label: 'Loyalty', model: 'loyaltyRules', step: null }
    ];

    /* ==============================
       FIELD MAPS (FIXES BUG)
    ============================== */
    c.textFieldMap = {
        name: 'nameRules',
        text: 'textRules',
        flavor: 'flavorRules',
        artist: 'artistRules',
        type: 'typeRules',
        rarity: 'rarityRules'
    };

    c.numericFieldMap = {
        cmc: 'cmcRules',
        price: 'priceRules',
        price_change: 'priceChangeRules',
        power: 'powerRules',
        toughness: 'toughnessRules',
        loyalty: 'loyaltyRules'
    };

    /* ==============================
       CARD SCALE
    ============================== */
    c.cardScale = (function() {
        var scale = 'm';
        try {
            var qScale = ($location.search().c) || null;
            if (!qScale && $scope.data && $scope.data.card_scale)
                qScale = $scope.data.card_scale;

            if (qScale && ['s', 'm', 'l'].indexOf(qScale) !== -1)
                scale = qScale;
        } catch (e) {
            scale = ($scope.data && $scope.data.card_scale) || 'm';
        }
        return scale;
    })();

    /* ==============================
       NAVIGATION
    ============================== */
    c.goToPage = function(page) {
        if (!page || page < 1) return;
        var params = angular.copy($location.search());
        params.p = page;
        $location.search(params);
    };

    c.nextPage = function() {
        if ($scope.data.pagination && $scope.data.pagination.has_next)
            c.goToPage($scope.data.pagination.page + 1);
    };

    c.prevPage = function() {
        if ($scope.data.pagination && $scope.data.pagination.has_prev)
            c.goToPage($scope.data.pagination.page - 1);
    };

    c.firstPage = function() { c.goToPage(1); };
    c.lastPage = function() {
        if ($scope.data.pagination)
            c.goToPage($scope.data.pagination.total_pages);
    };

    /* ==============================
       BASIC SEARCH
    ============================== */
    c.submitSearch = function() {
        var params = angular.copy($location.search());
        params.q = c.searchQuery;
        params.p = 1;
        $location.search(params);
    };

    /* ==============================
       TOGGLE ADVANCED SEARCH
    ============================== */
    c.toggleAdvancedSearch = function() {
        c._populateFromParsed(c.data.query);
        c.showAdvancedSearch = !c.showAdvancedSearch;
    };

    /* ==============================
       PARSE QUERY INTO UI
    ============================== */
    c._populateFromParsed = function(query) {
        if (!query) return;

        Object.keys(c.advQuery).forEach(k => {
            if (Array.isArray(c.advQuery[k])) c.advQuery[k] = [];
            else c.advQuery[k] = {};
        });

        var parsed = query.split(';');

        parsed.forEach(function(pair) {
            var parts = pair.split(':');
            if (parts.length !== 2) return;

            var key = parts[0].trim();
            var rawValue = decodeURIComponent(parts[1].trim());

            if (key === 'color') {
                rawValue.split(',').forEach(val => {
                    if (val) c.advQuery.colors[val] = true;
                });
                return;
            }

            var tokens = rawValue.split(/(&&|\|\|)/);
            var currentConnector = null;

            tokens.forEach(function(token) {

                if (token === '&&' || token === '||') {
                    currentConnector = token;
                    return;
                }

                if (!token) return;

                let operator = 'CONTAINS';
                let value = token;

                if (token.includes('|')) {
                    let split = token.split('|');
                    operator = split[0];
                    value = split.slice(1).join('|');
                }

                let map = c.textFieldMap;

                if (map[key]) {
                    c.advQuery[map[key]].push({
                        operator: operator,
                        value: value,
                        connector: currentConnector || '&&'
                    });
                }

                currentConnector = null;
            });
        });

        c.ensureRules();
    };

    /* ==============================
       RULE MANAGEMENT
    ============================== */
    c.addRule = function(field) {
        let numericFields = Object.values(c.numericFieldMap);

        c.advQuery[field].push(
            numericFields.includes(field)
                ? { operator: '>=', value: '', connector: '&&' }
                : { operator: 'CONTAINS', value: '', connector: '&&' }
        );
    };

    c.removeRule = function(field, index) {
        if (!c.advQuery[field]) return;

        c.advQuery[field].splice(index, 1);

        if (!c.advQuery[field].length)
            c.addRule(field);

        if (index === 0)
            c.advQuery[field].forEach(r => r.connector = null);
    };

    c.ensureRules = function() {
        Object.keys(c.advQuery).forEach(field => {
            if (Array.isArray(c.advQuery[field]) && !c.advQuery[field].length) {
                c.addRule(field);
            }
        });
    };

    /* ==============================
       QUERY BUILDERS
    ============================== */
    c.buildTextQuery = function(field, rules) {
        if (!Array.isArray(rules)) return null;

        let exp = '';

        rules.forEach((r, i) => {
            if (!r.value) return;

            if (i > 0)
                exp += (r.connector === '||') ? '%7C%7C' : '%26%26';

            exp += (r.operator || 'CONTAINS') + '|' + encodeURIComponent(r.value);
        });

        return exp ? field + ':' + exp : null;
    };

    c.buildNumericQuery = function(field, rules) {
        if (!Array.isArray(rules)) return null;

        let exp = '';

        rules.forEach((r, i) => {
            if (r.value === '' || r.value === null || r.value === undefined) return;

            if (i > 0)
                exp += (r.connector === '||') ? '%7C%7C' : '%26%26';

            exp += r.operator + r.value;
        });

        return exp ? field + ':' + exp : null;
    };

    /* ==============================
       SUBMIT ADVANCED SEARCH
    ============================== */
    c.submitAdvancedSearch = function() {
        var params = angular.copy($location.search());
        let queryParts = [];

        Object.keys(c.textFieldMap).forEach(key => {
            let rules = c.advQuery[c.textFieldMap[key]];
            let q = c.buildTextQuery(key, rules);
            if (q) queryParts.push(q);
        });

        Object.keys(c.numericFieldMap).forEach(key => {
            let rules = c.advQuery[c.numericFieldMap[key]];
            let q = c.buildNumericQuery(key, rules);
            if (q) queryParts.push(q);
        });

        let colors = Object.keys(c.advQuery.colors)
            .filter(k => c.advQuery.colors[k]);

        if (colors.length)
            queryParts.push('color:' + colors.join(','));

        params.q = queryParts.join(';');
        params.p = 1;

        $location.search(params);
        c.showAdvancedSearch = false;
    };

    /* ==============================
       INIT
    ============================== */
    c.ensureRules();
};

sp_widget.script:
(function() {

    /* ==============================
     * CONSTANTS
     * ============================== */
    const PARAMS = {
        DEBUG: 'db',
        DEBUG_METHODS: 'dbm'
    };

    /* ==============================
     * PARAM HELPERS
     * ============================== */
    function getStringParam(name, defaultValue) {
        var val = $sp.getParameter(name);
        return val ? val.toString() : defaultValue;
    }

    /* ==============================
     * USER CONTEXT
     * ============================== */
    const isLoggedIn = gs.getUserID() !== '';
    const isAdmin = gs.hasRole('admin');

    /* ==============================
     * DEBUG PARAMS
     * ============================== */
    const rawDebug = getStringParam(PARAMS.DEBUG, 'false');
    const rawDebugIgnoreMethods = getStringParam(PARAMS.DEBUG_METHODS, '');

    const debugEnabled = (
        (rawDebug === 'true' || rawDebug === '1') &&
        isLoggedIn &&
        isAdmin
    );

    const DebugIgnoreMethods = debugEnabled ? rawDebugIgnoreMethods : '';

    /* ==============================
     * SERVICES INIT
     * ============================== */
    const MTG_CONSTANTS = new x_759224_magic_c_0.mtg_constants(debugEnabled, DebugIgnoreMethods);
    const PORTAL_UTILS = new x_759224_magic_c_0.mtg_portal_utils(debugEnabled, DebugIgnoreMethods, $sp, MTG_CONSTANTS);

    /* ==============================
     * CONFIG
     * ============================== */
    const CONFIG = {
        table: MTG_CONSTANTS.tables.CARDS,
        search_fields: ['name'],
        fields: ['name', 'short_description', 'sys_created_on'],
        order_by: 'name'
    };

    /* ==============================
     * EXECUTION
     * ============================== */
    let countRes = PORTAL_UTILS.getCount(CONFIG.table, CONFIG.search_fields);
    let queryRes = PORTAL_UTILS.queryTable(CONFIG);
    // expose parsed query for client-side pre-population of advanced modal
    let parsedQueryRes = PORTAL_UTILS.parseQuery();
    let humanReadableQueryRes = PORTAL_UTILS.toHumanReadableQuery();
    if (humanReadableQueryRes.success) {
        data.human_readable_query = humanReadableQueryRes.record.human_readable;
    }else{
		data.human_readable_query = data.query;
	}
    let paginationRes = PORTAL_UTILS.getPagination(countRes.record);

    // Card scale param (c): s | m | l. Expose to client in `data.card_scale`.
    var rawScale = getStringParam('c', 'm');
    var cardScale = ['s', 'm', 'l'].indexOf(rawScale) !== -1 ? rawScale : 'm';
    if (debugEnabled) PORTAL_UTILS.log('init', 'card_scale=' + cardScale);

    /* ==============================
     * RESPONSE MAPPING
     * ============================== */
	data.records = queryRes.record || [];
    data.pagination = paginationRes.record || {};
    data.query = PORTAL_UTILS.query;
    data.parsedQuery = parsedQueryRes.record || {};
    data.card_scale = cardScale;
    data.debug = PORTAL_UTILS.debug;
	data.theme = gs.getUser().theme;


    /* ==============================
     * OPTIONAL ERROR SURFACING
     * ============================== */
    data.errors = [];
	if(data.debug){
		if (!countRes.success) data.errors.push(countRes.message);
		if (!queryRes.success) data.errors.push(queryRes.message);
		if (!paginationRes.success) data.errors.push(paginationRes.message);
	}

})();
